async (params, browser) => {
  // Open Slack
  await browser.open('https://app.slack.com')

  // Let Slack load
  await browser.wait(3000)

  // Delete message via Slack API
  const result = await browser.evaluate(`const localConfig = localStorage.getItem('localConfig_v2'); if (!localConfig) throw new Error('Not logged into Slack'); const config = JSON.parse(localConfig); const teamId = Object.keys(config.teams)[0]; const token = config.teams[teamId].token; const chanResp = await fetch('/api/conversations.list?types=public_channel,private_channel&limit=200', { method: 'POST', headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/x-www-form-urlencoded' } }); const chanData = await chanResp.json(); const channel = chanData.channels?.find(c => c.name === params.channel_name); if (!channel) return { success: false, message: 'Channel not found: ' + params.channel_name + '' }; const resp = await fetch('/api/chat.delete', { method: 'POST', headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' }, body: JSON.stringify({ channel: channel.id, ts: params.message_ts }) }); const data = await resp.json(); if (!data.ok) throw new Error('Delete failed: ' + data.error); return { success: true, channel: '' + params.channel_name + '', deleted_ts: '' + params.message_ts + '' }`)

  return result
}
